from dataclasses import dataclass

@dataclass
class Triple:
    subject: str
    predicate: str
    object: str

# EVOLVE-BLOCK-START

def predict(triples: list[Triple]) -> str:
    """
    Convert a list of triples about airports (or related entities) into a single
    fluent, complex sentence. Unknown predicates fall back to a generic phrasing.
    """
    if not triples:
        return ""

    def _clean(val: str) -> str:
        """Remove surrounding quotes if present."""
        return val.strip('"').strip("'")

    # Find the main subject (usually an airport)
    main_subject = None
    for t in triples:
        if "Airport" in t.subject or "Airport" in t.object:
            main_subject = t.subject
            break
    if not main_subject:
        main_subject = triples[0].subject

    # Helper to build a clause for a single triple
    def _clause(s: str, p: str, o: str, is_main: bool = False) -> str:
        # Primary airport‑specific predicates
        if p == "cityServed":
            return f"{s} serves the city of {o}" if is_main else f"serves the city of {o}"
        if p == "location":
            return f"{s} is located in {o}" if is_main else f"is located in {o}"
        if p == "country":
            return f"{s} is in {o}" if is_main else f"is in {o}"
        if p == "isPartOf":
            return f"{s} is part of {o}" if is_main else f"is part of {o}"
        if p == "elevationAboveTheSeaLevel":
            return f"{s} lies at an elevation of {o} metres above sea level" if is_main else f"lies at an elevation of {o} metres above sea level"
        if p == "elevationAboveTheSeaLevelInFeet":
            return f"{s} lies at an elevation of {o} feet above sea level" if is_main else f"lies at an elevation of {o} feet above sea level"
        if p == "elevationAboveTheSeaLevelInMetres":
            return f"{s} lies at an elevation of {o} metres above sea level" if is_main else f"lies at an elevation of {o} metres above sea level"
        if p == "operatingOrganisation":
            return f"{s} is operated by {o}" if is_main else f"is operated by {o}"
        if p == "runwaySurfaceType":
            return f"{s} has a runway surface of {o}" if is_main else f"has a runway surface of {o}"
        # Runway length variants
        if p.endswith("RunwayLengthFeet"):
            idx = p.split("Runway")[0]
            suffix = "st" if idx == "1" else "nd" if idx == "2" else "rd" if idx == "3" else "th"
            return f"{s}'s {idx}{suffix} runway is {o} feet long" if is_main else f"{idx}{suffix} runway is {o} feet long"
        if p.endswith("RunwayLengthMetre"):
            idx = p.split("Runway")[0]
            suffix = "st" if idx == "1" else "nd" if idx == "2" else "rd" if idx == "3" else "th"
            return f"{s}'s {idx}{suffix} runway is {o} metres long" if is_main else f"{idx}{suffix} runway is {o} metres long"
        # Runway identifiers
        if p == "runwayName":
            return f"{s}'s runway is named {o}" if is_main else f"runway is named {o}"
        if p == "runwayLength":
            return f"{s}'s runway length is {o}" if is_main else f"runway length is {o}"
        # Runway surface types
        if p.endswith("RunwaySurfaceType"):
            idx = p.split("Runway")[0]
            suffix = "st" if idx == "1" else "nd" if idx == "2" else "rd" if idx == "3" else "th"
            return f"{s}'s {idx}{suffix} runway surface is {o}" if is_main else f"{idx}{suffix} runway surface is {o}"
        if p.endswith("RunwayNumber"):
            idx = p.split("Runway")[0]
            suffix = "st" if idx == "1" else "nd" if idx == "2" else "rd" if idx == "3" else "th"
            return f"{s}'s {idx}{suffix} runway number is {o}" if is_main else f"{idx}{suffix} runway number is {o}"
        # Aviation codes
        if p == "iataLocationIdentifier":
            return f"{s} has IATA code {o}" if is_main else f"has IATA code {o}"
        if p == "icaoLocationIdentifier":
            return f"{s} has ICAO code {o}" if is_main else f"has ICAO code {o}"
        if p == "locationIdentifier":
            return f"{s} has location identifier {o}" if is_main else f"has location identifier {o}"
        # Ownership and administration
        if p == "owner":
            return f"{s} is owned by {o}" if is_main else f"is owned by {o}"
        if p == "largestCity":
            return f"The largest city of {s} is {o}" if is_main else f"largest city is {o}"
        if p == "capital":
            return f"The capital of {s} is {o}" if is_main else f"capital is {o}"
        if p == "language" or p == "officialLanguage":
            return f"The official language of {s} is {o}" if is_main else f"official language is {o}"
        if p == "leader":
            return f"The leader of {s} is {o}" if is_main else f"leader is {o}"
        if p == "leaderTitle":
            return f"The leader title of {s} is {o}" if is_main else f"leader title is {o}"
        if p == "leaderParty":
            return f"The leader of {s} belongs to the {o} party" if is_main else f"leader belongs to the {o} party"
        if p == "nativeName":
            return f"{s} is known as {o} in the native language" if is_main else f"known as {o} in the native language"
        # Fallback for any other predicate
        return f"{s} has {p} {o}" if is_main else f"has {p} {o}"

    # Build clauses
    clauses: list[str] = [
        _clause(t.subject, t.predicate, _clean(t.object), is_main=(t.subject == main_subject))
        for t in triples
    ]

    # Combine clauses into a single complex sentence
    if len(clauses) == 1:
        sentence = clauses[0] + "."
    else:
        sentence = ", ".join(clauses[:-1]) + ", and " + clauses[-1] + "."

    # Capitalise first character
    return sentence[0].upper() + sentence[1:]

# EVOLVE-BLOCK-END

